// Tránh zombie trong Node.js (child_process)

const { fork } = require('child_process');

const child = fork('./worker.js');

child.on('exit', (code) => {

  console.log('Child exited:', code);

  // child entry được cleanup tự động

});

// Hoặc dùng child.unref() cho detached process

child.unref(); // parent không chờ child

// Race condition example

let counter = 0;

// Thread 1:  LOAD counter (0)

//             ADD 1

//             STORE counter (1)

// Thread 2:  LOAD counter (0)  <- giữa Thread 1!

//             ADD 1

//             STORE counter (1)  <- mất 1 update!

// Expected: counter = 2, Got: counter = 1

// Solution: Mutex lock

mutex.lock();

counter++;

mutex.unlock();

// Semaphore đếm connections

const semaphore = new Semaphore(5); // max 5 concurrent DB connections

async function query(sql) {

  await semaphore.acquire();  // wait nếu đủ 5 connections

  try {

    return await db.execute(sql);

  } finally {

    semaphore.release();       // giải phóng slot

  }

}

// Anonymous pipe: chỉ giữa related processes

// Shell: ls | grep .js

