// Event loop tiếp tục xử lý requests khác trong lúc chờ

// Peterson's algorithm

// Tấc cả 3 conditions: mutual exclusion, progress, bounded waiting

let flag = [false, false]; // flag[i] = process i wants to enter CS

let turn = 0;              // whose turn

// Process i wants critical section:

function enterCS(i) {

  const j = 1 - i;

  flag[i] = true;  // i wants to enter

  turn = j;        // give priority to j

  while (flag[j] && turn === j) {} // busy wait

}

function exitCS(i) {

  flag[i] = false; // i is done

}
